theme.stylesheet:
/* ── Window frame ────────────────────────────────────────────────────────── */
/* The 3px raised frame is padding on the window; the inert frame-edge
   overlay paints the bevel on top so scrollable content slides under it. */
[data-theme="win98"] [data-part="window"] {
  padding: var(--window-frame-w);
  box-shadow: var(--window-shadow);
}

[data-theme="win98"] [data-part="window-frame-edge"] {
  box-shadow:
    inset -1px -1px var(--bevel-darker),
    inset 1px 1px var(--bevel-light),
    inset -2px -2px var(--bevel-dark),
    inset 2px 2px var(--bevel-lighter);
}

/* ── Titlebar ────────────────────────────────────────────────────────────── */
[data-theme="win98"] [data-part="titlebar"] {
  background: var(--titlebar-bg);
  color: var(--titlebar-fg);
  padding: 2px 2px 2px 3px;
  margin-bottom: 1px; /* the hairline of face gray between caption and menu/toolbar */
}

[data-theme="win98"] [data-part="window"][data-focused="false"] [data-part="titlebar"] {
  background: var(--titlebar-bg-inactive);
  color: var(--titlebar-fg-inactive);
}

[data-theme="win98"] [data-part="title"] {
  font-weight: bold;
  padding: 0 4px 0 2px;
}

[data-theme="win98"] [data-part="title-icon"] {
  margin-left: 1px;
}

[data-theme="win98"] [data-part="title-icon"] svg {
  width: 16px;
  height: 16px;
}

/* ── Caption buttons (declarative controlGlyphs) ──────────────────────────── */
[data-theme="win98"] [data-part="controls"] {
  gap: 0;
}

[data-theme="win98"] [data-part="control"] {
  width: 16px;
  height: 14px;
  background: var(--control-bg);
  color: var(--control-fg);
  box-shadow: var(--x-win98-bevel-raised);
}

/* Caption buttons never show a focus marquee. */
[data-theme="win98"] [data-part="control"]:focus-visible {
  outline: none;
}

[data-theme="win98"] [data-part="control"][data-action="close"] {
  margin-left: 2px;
}

[data-theme="win98"] [data-part="control"]:active {
  box-shadow: var(--x-win98-bevel-pressed);
}

[data-theme="win98"] [data-part="control"]:active svg {
  transform: translate(1px, 1px);
}

/* ── Toolbar (IE4 idiom: flat buttons, bevel appears on hover) ──────────── */
[data-theme="win98"] [data-part="toolbar"] {
  background: var(--toolbar-bg);
  box-shadow: var(--x-win98-bevel-thin-raised);
  gap: 4px;
  padding: 0 4px;
}

[data-theme="win98"] [data-part="toolbar-group"] {
  gap: 0;
}

[data-theme="win98"] [data-part="toolbar-button"] {
  height: 24px;
  min-width: 24px;
  padding: 0 5px;
  background: transparent;
  color: var(--control-fg);
}

[data-theme="win98"] [data-part="toolbar-button"]:hover:not(:disabled) {
  box-shadow: var(--x-win98-bevel-thin-raised);
}

[data-theme="win98"] [data-part="toolbar-button"]:active:not(:disabled),
[data-theme="win98"] [data-part="toolbar-button"][data-state="active"] {
  box-shadow: var(--x-win98-bevel-thin-sunken);
}

/* Toggled-on toolbar buttons get the classic dither wash. */
[data-theme="win98"] [data-part="toolbar-button"][data-state="active"] {
  background-image: var(--x-win98-dither);
  background-size: 2px 2px;
}

[data-theme="win98"] [data-part="toolbar-button"]:active:not(:disabled) > *,
[data-theme="win98"] [data-part="toolbar-button"][data-state="active"] > * {
  transform: translate(1px, 1px);
}

[data-theme="win98"] [data-part="toolbar-button"]:disabled {
  color: var(--fg-disabled);
  text-shadow: 1px 1px 0 var(--bevel-lighter); /* engraved disabled text */
}

/* ── Breadcrumbs as the Explorer address bar: a sunken white well ────────── */
[data-theme="win98"] [data-part="breadcrumbs"] {
  flex: 1;
  height: 22px;
  padding: 2px 4px;
  background: var(--input-bg);
  box-shadow: var(--x-win98-bevel-sunken);
}

[data-theme="win98"] [data-part="breadcrumb"] {
  height: 16px;
  padding: 0 3px;
  color: var(--fg);
}

[data-theme="win98"] [data-part="breadcrumb"]:hover {
  background: var(--selection-bg);
  color: var(--selection-fg);
}

[data-theme="win98"] [data-part="breadcrumb"][data-state="current"] {
  font-weight: bold;
}

[data-theme="win98"] [data-part="breadcrumbs"] svg {
  color: var(--fg-muted);
}

/* ── Search field: a sunken edit control ─────────────────────────────────── */
[data-theme="win98"] [data-part="search-field"] {
  height: 22px;
  min-width: 140px;
  padding: 2px 4px;
  background: var(--input-bg);
  color: var(--input-fg);
  box-shadow: var(--x-win98-bevel-sunken);
}

[data-theme="win98"] [data-part="search-field"] svg {
  color: var(--fg-muted);
}

[data-theme="win98"] [data-part="search-field"] input::placeholder {
  color: var(--fg-disabled);
}

/* ── Split panes: white sunken wells over the gray body ──────────────────── */
[data-theme="win98"] [data-part="window-body"] {
  background: var(--bg);
}

[data-theme="win98"] [data-part="split-view"] {
  padding: 2px;
}

[data-theme="win98"] [data-part="split-divider"] {
  background: var(--surface);
}

/* ── Sidebar (the Explorer folder tree pane) ─────────────────────────────── */
[data-theme="win98"] [data-part="sidebar"] {
  background: var(--sidebar-bg);
  color: var(--sidebar-fg);
  box-shadow: var(--x-win98-bevel-sunken);
  padding: 2px;
}

[data-theme="win98"] [data-part="sidebar-heading"] {
  background: var(--surface);
  box-shadow: var(--x-win98-bevel-thin-raised);
  font-size: 11px;
  padding: 2px 6px;
  margin-bottom: 2px;
}

[data-theme="win98"] [data-part="sidebar-section"] + [data-part="sidebar-section"] {
  margin-top: 6px;
}

[data-theme="win98"] [data-part="sidebar-item"] {
  padding: 0 4px;
  color: var(--sidebar-fg);
}

[data-theme="win98"] [data-part="sidebar-item"][data-state="selected"] {
  background: var(--sidebar-selected-bg);
  color: var(--sidebar-selected-fg);
}

[data-theme="win98"] [data-part="sidebar-item"][data-state="selected"]:focus-visible {
  outline: 1px dotted var(--sidebar-selected-fg);
  outline-offset: -1px;
}

/* Inline eject on removable-volume rows: flat at rest like a coolbar button,
   raising/sinking the thin bevel on hover/press — tab-close's bevel language. */
[data-theme="win98"] [data-part="sidebar-item-action"] {
  width: 14px;
  height: 14px;
  color: var(--fg-muted);
}

[data-theme="win98"] [data-part="sidebar-item-action"]:hover {
  box-shadow: var(--x-win98-bevel-thin-raised);
  color: var(--fg);
}

[data-theme="win98"] [data-part="sidebar-item-action"]:active {
  box-shadow: var(--x-win98-bevel-thin-sunken);
}

[data-theme="win98"] [data-part="sidebar-item"][data-state="selected"] [data-part="sidebar-item-action"] {
  color: var(--sidebar-selected-fg);
}

/* ── File list (Explorer details view) ───────────────────────────────────── */
[data-theme="win98"] [data-part="file-list"] {
  background: var(--list-bg);
  box-shadow: var(--x-win98-bevel-sunken);
}

[data-theme="win98"] [data-part="file-list"]:focus-visible {
  outline: none; /* focus shows on the selected row, not the well */
}

/* Header cells are raised gray buttons; stretch so the bevels meet. */
[data-theme="win98"] [data-part="file-list-header"] {
  align-items: stretch;
  background: var(--list-header-bg);
}

[data-theme="win98"] [data-part="file-list-col"] {
  display: flex;
  align-items: center;
  background: var(--list-header-bg);
  color: var(--list-header-fg);
  box-shadow: var(--x-win98-bevel-raised);
  font-size: 11px;
  padding: 0 6px;
}

[data-theme="win98"] [data-part="file-list-col"][data-col="size"] {
  justify-content: flex-end;
}

[data-theme="win98"] [data-part="file-list-col"][data-state="sorted"] {
  box-shadow: var(--x-win98-bevel-pressed);
  padding: 1px 5px 0 7px; /* the pressed 1px content nudge */
}

/* No row hover in this era — selection only. */
[data-theme="win98"] [data-part="file-row"][data-state="selected"] {
  background: var(--selection-bg);
  color: var(--selection-fg);
}

/* Keyboard focus draws the dotted marquee inside the selection. */
[data-theme="win98"] [data-part="file-list"]:focus [data-part="file-row"][data-state="selected"] {
  outline: 1px dotted var(--selection-fg);
  outline-offset: -1px;
}

/* Classic listview: selection drops to button-face gray when not key. */
[data-theme="win98"] [data-part="window"][data-focused="false"] [data-part="file-row"][data-state="selected"],
[data-theme="win98"] [data-part="window"][data-focused="false"] [data-part="sidebar-item"][data-state="selected"] {
  background: var(--surface);
  color: var(--fg);
}

/* ── Icon grid: the label inverts to selection blue, like the 9x desktop ── */
[data-theme="win98"] [data-part="icon-grid"] {
  background: var(--list-bg);
}
[data-theme="win98"] [data-part="icon-grid-label"] {
  padding: 0 2px;
}
[data-theme="win98"] [data-part="icon-grid-item"][data-state="selected"] [data-part="icon-grid-label"] {
  background: var(--selection-bg);
  color: var(--selection-fg);
  outline: 1px dotted var(--selection-fg);
  outline-offset: -1px;
}
[data-theme="win98"] [data-part="icon-grid-item"][data-state="selected"] [data-part="icon-grid-icon"] {
  filter: brightness(0.75) sepia(0.4) hue-rotate(180deg);
}

[data-theme="win98"] [data-part="list-empty"] {
  color: var(--fg-muted);
}

/* ── Terminal panel: pure DOS in a sunken well ───────────────────────────── */
[data-theme="win98"] [data-part="terminal-panel"] {
  background: var(--surface);
  border-top: 1px solid var(--bevel-lighter);
}

[data-theme="win98"] [data-part="terminal-panel"][data-state="closed"] {
  border-top: none;
}

[data-theme="win98"] [data-part="terminal-header"] {
  height: 20px;
  padding: 0 6px;
  font-size: 11px;
  font-weight: bold;
}

[data-theme="win98"] [data-part="terminal-host"] {
  margin: 0 2px 2px;
  padding: 3px;
  background: var(--terminal-bg);
  color: var(--terminal-fg);
  box-shadow: var(--x-win98-bevel-sunken);
  font-family: var(--font-mono);
}

/* ── Status bar: sunken cells + resize grip ──────────────────────────────── */
[data-theme="win98"] [data-part="status-bar"] {
  height: 22px;
  padding: 2px;
  gap: 2px;
  background: var(--surface);
}

[data-theme="win98"] [data-part="status-item"] {
  height: 100%;
  padding: 0 6px;
  box-shadow: var(--x-win98-bevel-thin-sunken);
}

/* The first cell flexes so trailing cells right-align, Explorer-style. */
[data-theme="win98"] [data-part="status-item"]:first-child {
  flex: 1;
}

/* Diagonal-ridge size grip in the corner. */
[data-theme="win98"] [data-part="status-bar"]::after {
  content: "";
  flex: none;
  width: 12px;
  height: 12px;
  align-self: flex-end;
  background: repeating-linear-gradient(
    135deg,
    var(--surface) 0 1px,
    var(--bevel-lighter) 1px 2px,
    var(--bevel-dark) 2px 4px
  );
  clip-path: polygon(100% 0, 100% 100%, 0 100%);
}

/* ── Generic controls ────────────────────────────────────────────────────── */
[data-theme="win98"] [data-part="button"],
[data-theme="win98"] [data-part="icon-button"],
[data-theme="win98"] [data-part="segment"] {
  min-height: 22px;
  padding: 0 10px;
  background: var(--control-bg);
  color: var(--control-fg);
  box-shadow: var(--control-shadow);
  border-radius: var(--control-radius);
}

[data-theme="win98"] [data-part="icon-button"] {
  min-width: 22px;
  padding: 0 4px;
}

[data-theme="win98"] [data-part="button"]:active:not(:disabled),
[data-theme="win98"] [data-part="button"][data-state="open"],
[data-theme="win98"] [data-part="icon-button"]:active:not(:disabled),
[data-theme="win98"] [data-part="segment"]:active:not(:disabled),
[data-theme="win98"] [data-part="segment"][data-state="selected"] {
  box-shadow: var(--x-win98-bevel-pressed);
}

[data-theme="win98"] [data-part="button"]:active:not(:disabled) > *,
[data-theme="win98"] [data-part="icon-button"]:active:not(:disabled) > *,
[data-theme="win98"] [data-part="segment"]:active:not(:disabled) > * {
  transform: translate(1px, 1px);
}

/* A toggled-on segment shows the dither wash like a latched toolbar button. */
[data-theme="win98"] [data-part="segment"][data-state="selected"] {
  background-image: var(--x-win98-dither);
  background-size: 2px 2px;
}

[data-theme="win98"] [data-part="button"]:disabled,
[data-theme="win98"] [data-part="icon-button"]:disabled,
[data-theme="win98"] [data-part="segment"]:disabled {
  color: var(--fg-disabled);
  text-shadow: 1px 1px 0 var(--bevel-lighter);
}

/* ── Menus ───────────────────────────────────────────────────────────────── */
[data-theme="win98"] [data-part="menu"] {
  background: var(--surface);
  color: var(--fg);
  box-shadow: var(--x-win98-bevel-raised);
  padding: 1px;
}

[data-theme="win98"] [data-part="menu-item"] {
  height: 18px;
  padding: 1px 18px 1px 8px;
}

[data-theme="win98"] [data-part="menu-item"]:hover:not([aria-disabled="true"]),
[data-theme="win98"] [data-part="menu-item"]:focus:not([aria-disabled="true"]) {
  background: var(--selection-bg);
  color: var(--selection-fg);
  outline: none;
}

[data-theme="win98"] [data-part="menu-item"][aria-disabled="true"] {
  color: var(--fg-disabled);
  text-shadow: 1px 1px 0 var(--bevel-lighter);
}

[data-theme="win98"] [data-part="menu-separator"] {
  height: 0;
  border-top: 1px solid var(--bevel-dark);
  border-bottom: 1px solid var(--bevel-lighter);
  margin: 3px 1px;
}

/* ── Scrollbars: gray bevel thumb over the dither track ──────────────────── */
[data-theme="win98"] ::-webkit-scrollbar-track {
  background-color: var(--scrollbar-track);
  background-image: var(--x-win98-dither);
  background-size: 2px 2px;
}

[data-theme="win98"] ::-webkit-scrollbar-thumb {
  background: var(--scrollbar-thumb);
  box-shadow: var(--x-win98-bevel-raised);
}

[data-theme="win98"] ::-webkit-scrollbar-corner {
  background: var(--surface);
}

[data-theme="win98"] ::-webkit-scrollbar-button {
  display: none; /* arrow-less; the bevel thumb carries the look */
}

/* ── In-page tabs (⌘T) — classic property-sheet tabs on button-face gray ── */
[data-theme="win98"] [data-part="tab-bar"] {
  background: var(--surface);
  padding: 3px 3px 0;
  gap: 0;
  /* The selected tab fuses with the toolbar below; the strip draws no line. */
}

[data-theme="win98"] [data-part="tab"] {
  height: 21px;
  min-height: 21px;
  background: var(--control-bg);
  color: var(--control-fg);
  border-radius: 2px 2px 0 0;
  box-shadow: var(--x-win98-bevel-raised);
  margin-top: 2px;
}

[data-theme="win98"] [data-part="tab"][data-state="selected"] {
  /* The active sheet tab stands 2px prouder and bolds its caption. */
  margin-top: 0;
  height: 23px;
  min-height: 23px;
  font-weight: bold;
}

[data-theme="win98"] [data-part="tab-close"],
[data-theme="win98"] [data-part="tab-add"] {
  width: 14px;
  height: 14px;
  font-size: 11px;
  line-height: 1;
  background: var(--control-bg);
  box-shadow: var(--x-win98-bevel-thin-raised);
}

[data-theme="win98"] [data-part="tab-close"]:active,
[data-theme="win98"] [data-part="tab-add"]:active {
  box-shadow: var(--x-win98-bevel-thin-sunken);
}

[data-theme="win98"] [data-part="tab-add"] {
  align-self: center;
  margin: 0 3px;
}

/* ── Modal dialogs: a classic gray dialog with its own caption strip ─────── */
[data-theme="win98"] [data-part="dialog-overlay"] {
  background: transparent; /* the era never dimmed the desktop */
}

[data-theme="win98"] [data-part="dialog"] {
  background: var(--surface);
  border: none;
  border-radius: 0;
  box-shadow: var(--x-win98-bevel-raised);
  padding: 3px;
  gap: 0;
}

[data-theme="win98"] [data-part="dialog-title"] {
  background: var(--titlebar-bg);
  color: var(--titlebar-fg);
  font-size: 11px;
  font-weight: 700;
  padding: 3px 6px;
  margin-bottom: 10px;
}

[data-theme="win98"] [data-part="dialog-body"] {
  padding: 2px 10px;
}

[data-theme="win98"] [data-part="dialog-actions"] {
  padding: 12px 10px 8px;
}

[data-theme="win98"] [data-part="text-input"] {
  border: none;
  border-radius: 0;
  box-shadow: var(--x-win98-bevel-sunken);
  padding: 4px 6px;
}
